// Any MEC automation that fails (and lists this as its error workflow) lands here → alert the team
// via the portal, which WhatsApps everyone + logs to Supabase error_log.
const e = $json || {};
const wf = (e.workflow && e.workflow.name) || 'unknown workflow';
const node = (e.execution && e.execution.lastNodeExecuted) || '';
const err = (e.execution && e.execution.error) || {};
const msg = err.message || err.description || JSON.stringify(e).slice(0, 600);
const base = $env.PORTAL_BASE_URL;
const secret = $env.WASENDER_WEBHOOK_SECRET;
try {
  await this.helpers.httpRequest({ method: 'POST', url: base + '/api/report-error?key=' + encodeURIComponent(secret), body: { source: 'n8n:' + wf, message: String(msg), context: node ? ('node ' + node) : 'n8n automation' }, json: true });
} catch (err2) {}
return [{ json: { reported: true, workflow: wf } }];
